INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('11-media-network',2,11,'MEDIA NETWORK','Xay dung mang luoi media',11,'draft','2026-06-20T11:08:50Z','2026-06-20T11:08:50Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0bb63903-5057-45a8-a465-8e51b02709ca','11-media-network',NULL,2,'11.1 Media Network là gì?','111-media-network-la-gi',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eab02213-d8c3-4c93-b85a-b0862885b966','0bb63903-5057-45a8-a465-8e51b02709ca',0,'image',NULL,'book/11-media-network/ec647121-7283-4792-b511-96d91d8a25fc-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5bd4e6f-60db-4ac0-aec2-f61991aa5346','0bb63903-5057-45a8-a465-8e51b02709ca',1,'text','Dental Media System có thể được định nghĩa là hệ thống truyền thông giúp phòng khám nha khoa đi từ thu hút khách hàng mới đến xây dựng niềm tin, chuyển đổi thành lịch hẹn và cuối cùng tạo tăng trưởng bền vững thông qua website, SEO và dữ liệu khách hàng. Cấu trúc này cho thấy mục tiêu của truyền thông không chỉ là tăng độ phủ, mà còn là tổ chức hành vi khách hàng theo một lộ trình có thể kiểm soát và đo lường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('91db8958-6d9f-4708-9913-c5552fdebb48','0bb63903-5057-45a8-a465-8e51b02709ca',2,'text','Về bản chất, Media Network trả lời cho câu hỏi: phòng khám sẽ hiện diện ở đâu, bằng loại nội dung nào, và với vai trò gì trong hành trình ra quyết định của khách hàng. Vì vậy, thay vì xem truyền thông như hoạt động quảng bá ngắn hạn, hệ thống này đặt truyền thông vào vị trí của một năng lực vận hành cốt lõi, có thể đo lường, chuẩn hóa và mở rộng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08f40933-8f91-4ad4-8f4a-0a94ab723f80','0bb63903-5057-45a8-a465-8e51b02709ca',3,'text','Trong mô hình này, mỗi nền tảng đều đảm nhiệm một chức năng riêng. Các kênh social như TikTok, Reels, Shorts và Zalo Video tạo ra traffic; Facebook, YouTube, Zalo cá nhân và livestream tạo trust; Zalo Chat, inbox, page phòng khám, Google Map và gọi điện hỗ trợ conversion; còn website, blog, booking, SEO và GEO tạo tài sản dài hạn và năng lực hiện diện trên cả công cụ tìm kiếm lẫn hệ thống AI. Chính sự phân tầng này khiến hệ thống truyền thông trở thành một cấu trúc chiến lược thay vì một tập hợp công cụ rời rạc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00ddd78a-b028-4c48-9076-6496eaa90ff7','0bb63903-5057-45a8-a465-8e51b02709ca',4,'text','Media Network chính là “mạng lưới xuất hiện” của thương hiệu trong không gian số. Mạng lưới này không chỉ giúp khách hàng biết đến phòng khám, mà còn giúp họ kiểm chứng, so sánh và dần hình thành sự tin cậy trước khi quyết định đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc775b67-c533-44c2-a7f0-89c59c481727','0bb63903-5057-45a8-a465-8e51b02709ca',5,'text','Chúng ta cần xây dựng một hệ thống có đủ 5 tầng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e98e6d37-3631-48d5-9a55-e6c125260404','0bb63903-5057-45a8-a465-8e51b02709ca',6,'image',NULL,'book/11-media-network/cf886488-23cc-4460-b6ce-e762ca99b4cc-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b856c482-6600-4d76-bb52-c8c1661935f0','0bb63903-5057-45a8-a465-8e51b02709ca',7,'text','- **Traffic:** tạo sự chú ý.- **Trust:** xây dựng niềm tin.- **Conversion:** chuyển đổi thành lịch hẹn.- **Website & SEO:** tích lũy tài sản tìm kiếm dài hạn.- **GEO:** tối ưu để các công cụ AI như ChatGPT, Gemini, Perplexity, Google AI Overview hiểu, trích dẫn và gợi ý phòng khám khi người dùng hỏi về nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e0280808-2500-4b76-817b-4c6356b7761d','11-media-network',NULL,2,'11.2 Cấu trúc học thuật của Media Network','112-cau-truc-hoc-thuat-cua-media-network',1,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1d51ebc6-3c04-48b1-b213-39eb5067bc2c','11-media-network','e0280808-2500-4b76-817b-4c6356b7761d',3,'Social và Search','social-va-search',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02cbc9e0-f1b6-42e1-90f3-cf3c4a27d060','1d51ebc6-3c04-48b1-b213-39eb5067bc2c',8,'image',NULL,'book/11-media-network/b9c99104-ff34-45fc-bf15-770ac2bd48ca-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb3cda55-0855-46de-89ef-3d1241b3f276','1d51ebc6-3c04-48b1-b213-39eb5067bc2c',9,'text','Các kênh trong Media Network có thể phân thành hai cụm chức năng lớn là Social và Search. Social gồm TikTok, Facebook Reels, YouTube Shorts, Zalo Video và các hoạt động livestream; nhóm này có nhiệm vụ chính là tạo tiếp xúc ban đầu, kích hoạt sự chú ý và mở rộng độ phủ thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21768787-4e11-4043-b988-08a03846f8ca','1d51ebc6-3c04-48b1-b213-39eb5067bc2c',10,'text','Search gồm website, blog, Google Search, Google Business Profile, SEO và GEO; nhóm này đóng vai trò hỗ trợ khách hàng chủ động tìm kiếm thông tin khi nhu cầu đã hình thành rõ hơn. Nói cách khác, Social tạo sự hiện diện ban đầu, còn Search củng cố tính bền vững của sự hiện diện đó bằng khả năng truy xuất, giải thích và được trích dẫn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57ab6cf8-659a-4846-a843-5c66daf17f7c','1d51ebc6-3c04-48b1-b213-39eb5067bc2c',11,'text','Bên cạnh đó, Zalo giữ vị trí đặc biệt trong hệ thống vì nó gắn với quan hệ thật và dữ liệu liên hệ thật. Trong thực hành, Zalo không chỉ là công cụ nhắn tin mà còn là lớp trung gian giúp phòng khám nuôi dưỡng khách hàng cũ, chăm sóc khách đang điều trị và chuyển đổi những người còn do dự thành lịch hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3c67bd49-0f3f-4df8-b6b6-0d1fe0c4ddac','11-media-network','e0280808-2500-4b76-817b-4c6356b7761d',3,'Tầng nội dung và tầng bằng chứng','tang-noi-dung-va-tang-bang-chung',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36d82065-8ca0-4188-86cc-1b430c79f3fc','3c67bd49-0f3f-4df8-b6b6-0d1fe0c4ddac',12,'text','Một Media Network hoàn chỉnh không chỉ cần nội dung hay, mà còn cần bằng chứng đáng tin. Đó là lý do hệ thống này gắn chặt với Trust Assets như case trước/sau, Review Google Map, testimonial, hồ sơ bác sĩ, chứng chỉ, hình ảnh phòng khám, livestream chuyên môn và website chuyên nghiệp. Nội dung trả lời câu hỏi “phòng khám nói gì”, còn trust assets trả lời câu hỏi “phòng khám có đáng tin hay không”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0fdfe218-985f-48a0-8839-28f195e849c3','3c67bd49-0f3f-4df8-b6b6-0d1fe0c4ddac',13,'text','Sự kết hợp giữa nội dung và bằng chứng tạo nên một cấu trúc thuyết phục hoàn chỉnh. Nếu chỉ có nội dung mà thiếu bằng chứng, khách hàng có thể dừng lại ở mức quan tâm. Ngược lại, nếu có bằng chứng nhưng thiếu hệ thống nội dung, phòng khám khó tạo sự chú ý ban đầu. Vì vậy, vai trò của Media Network không chỉ là phân phối thông tin, mà là xây dựng một kiến trúc thuyết phục theo từng tầng nhận thức của khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('01bd00f0-2ed4-4594-9b33-ffa75b4bbcf7','11-media-network',NULL,2,'11.3 Vai trò chiến lược của Media Network','113-vai-tro-chien-luoc-cua-media-network',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11b33d24-01e7-4e86-9039-d2d3fc0adc7a','01bd00f0-2ed4-4594-9b33-ffa75b4bbcf7',14,'text','Từ góc độ chiến lược, Media Network giúp phòng khám giảm phụ thuộc vào một kênh duy nhất và thay thế tư duy “mua traffic” bằng tư duy “xây hệ sinh thái xuất hiện”. Khi các kênh social, search và trust assets được liên kết chặt chẽ, phòng khám có thể tạo ra dòng khách ổn định hơn, đồng thời tích lũy được tài sản thương hiệu có giá trị dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7121d28c-c5c6-4b5b-be32-534cc34fc8b4','01bd00f0-2ed4-4594-9b33-ffa75b4bbcf7',15,'image',NULL,'book/11-media-network/89a71235-810a-4a07-b8a8-8f3e8d85586a-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79927e1a-db64-4366-9c0f-99c8881c01dd','01bd00f0-2ed4-4594-9b33-ffa75b4bbcf7',16,'text','Quan trọng hơn, Media Network là lớp nền để các module khác trong Dental OS hoạt động hiệu quả hơn, đặc biệt là Marketing OS, Sales OS, Referral OS và Data OS. Vì vậy, trong cấu trúc của Dental Empire, Media Network không chỉ là một phần của marketing, mà là một điều kiện nền để thương hiệu vận hành như một hệ sinh thái tăng trưởng hoàn chỉnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('36ccdede-dd96-460c-8a1c-084f21379118','11-media-network',NULL,2,'11.4 Tại sao nội dung là tài sản chứ không chỉ là marketing?','114-tai-sao-noi-dung-la-tai-san-chu-khong-chi-la-marketing',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb5d8c38-7377-4626-b6a5-c29191d56914','36ccdede-dd96-460c-8a1c-084f21379118',17,'text','Trong hệ sinh thái Dental Empire, nội dung không được xem chỉ là công cụ marketing, mà là một loại tài sản tích lũy. Lý do là vì nội dung có thể tiếp tục tạo giá trị sau thời điểm xuất bản ban đầu: một bài viết chuyên sâu, một case study, một video bác sĩ, hay một trang FAQ có thể tiếp tục hỗ trợ niềm tin, tìm kiếm và chuyển đổi trong thời gian dài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1674508f-af1d-44f8-a104-37eec4ac9f07','36ccdede-dd96-460c-8a1c-084f21379118',18,'text','Nội dung có thể trở thành “Trust Assets” khi nó được tổ chức thành thư viện Case, Review, hồ sơ bác sĩ, website chuyên nghiệp, video feedback và tài liệu giáo dục. Khi đó, nội dung không chỉ là thứ để “đăng bài”, mà trở thành một kho bằng chứng giúp phòng khám gia tăng Authority, giảm rào cản ra quyết định và tạo nền tảng cho tăng trưởng bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('376c79d9-54e4-4eeb-ac57-449f56bd7868','11-media-network',NULL,2,'11.5 Hệ quả quản trị và đo lường','115-he-qua-quan-tri-va-o-luong',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a854872d-fdc7-4006-bd24-a3c5500ea01f','376c79d9-54e4-4eeb-ac57-449f56bd7868',19,'text','Khi Media Network được xem như một hệ thống, quản trị truyền thông cũng phải được chuyển từ cảm tính sang đo lường. Ở tầng Traffic, cần theo dõi số video đăng, lượt xem, thời gian xem, follower và inbox. Ở tầng Trust, cần quan sát số case, feedback, lượt xem livestream và lượng tương tác chất lượng. Ở tầng Conversion, cần theo dõi số tin nhắn mới, số khách add Zalo, tốc độ phản hồi, số lịch hẹn và tỷ lệ đến đúng hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb996152-aaa5-4a92-a574-a62f9347b825','376c79d9-54e4-4eeb-ac57-449f56bd7868',20,'text','Bên cạnh đó, website/SEO và GEO cũng cần được đo bằng các chỉ số riêng như truy cập website, từ khóa lên top, số form booking, số cuộc gọi từ website, branded search, số lượt AI/referral và mức độ đồng nhất thông tin thương hiệu trên nhiều nền tảng. Cách tiếp cận này cho phép phòng khám nhìn thấy chính xác tầng nào đang hiệu quả và tầng nào đang rơi khách, từ đó điều chỉnh chiến lược một cách có cơ sở.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0fa33608-11ed-48c2-80b5-cba79db33c1e','11-media-network',NULL,2,'11.6 Media Network hỗ trợ Customer Journey ra sao?','116-media-network-ho-tro-customer-journey-ra-sao',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b25c5fa-7606-4427-a54d-d30cc7d2ac8c','0fa33608-11ed-48c2-80b5-cba79db33c1e',21,'image',NULL,'book/11-media-network/5e3731b4-91f8-4666-bf22-5d7115033b28-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76f2266c-060a-49c4-a2cb-f6f9051eee6d','0fa33608-11ed-48c2-80b5-cba79db33c1e',22,'text','Media Network hỗ trợ Customer Journey bằng cách bám theo logic chuyển dịch từ Traffic sang Trust, rồi đến Relationship, Authority Check, Search Layer và Conversion. Ở giai đoạn đầu, nội dung ngắn trên TikTok, Reels hoặc Shorts giúp phòng khám tiếp cận người lạ và thu hút sự chú ý; ở giai đoạn tiếp theo, Facebook, YouTube và Livestream giúp tăng chiều sâu chuyên môn và niềm tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29272225-3bcc-480a-80c1-d224f4c48502','0fa33608-11ed-48c2-80b5-cba79db33c1e',23,'text','Khi khách hàng đã có nhu cầu rõ hơn, các kênh như Zalo, inbox, hotline, website và Google Map trở thành nơi xác nhận uy tín và hỗ trợ đặt lịch. Tài liệu cho thấy hành vi ra quyết định trong nha khoa thường không diễn ra ngay sau một lần chạm; khách hàng thường cần quan sát nhiều điểm chạm, so sánh nhiều nguồn và kiểm tra độ tin cậy trước khi bước vào phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5fb9c067-a56d-4d7c-8f03-e95ec71166ce','0fa33608-11ed-48c2-80b5-cba79db33c1e',24,'text','Từ góc nhìn này, Media Network không kết thúc ở việc “gây chú ý”, mà tiếp tục đóng vai trò trong toàn bộ chuỗi trải nghiệm trước và sau điều trị. Điều đó làm cho truyền thông trở thành một phần của hệ điều hành tăng trưởng, chứ không còn là hoạt động tách rời khỏi vận hành hay chăm sóc bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b907469f-987b-4585-b3b6-72f5d2a8f438','11-media-network',NULL,2,'11.7 Các loại nội dung trong hệ sinh thái Dental Empire','117-cac-loai-noi-dung-trong-he-sinh-thai-dental-empire',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('64119f86-cfcb-4adf-84ea-63f439588cb6','b907469f-987b-4585-b3b6-72f5d2a8f438',25,'text','Nội dung trong Dental Empire thường được tổ chức thành nhiều lớp, nhưng có thể quy về năm nhóm cơ bản: giáo dục, case điều trị, feedback/review, nội dung bác sĩ cá nhân và nội dung chuyển đổi. Nhóm giáo dục giúp khách hàng hiểu vấn đề răng miệng của mình; nhóm case điều trị chứng minh năng lực chuyên môn; nhóm feedback và review củng cố niềm tin xã hội; nhóm bác sĩ cá nhân xây dựng authority; còn nhóm chuyển đổi hướng khách hàng đến hành động cụ thể như nhắn Zalo, gọi điện hoặc đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02ed2da2-2107-42a5-8b1f-cdfa7107e74d','b907469f-987b-4585-b3b6-72f5d2a8f438',26,'image',NULL,'book/11-media-network/adebfa79-e827-47b8-bce0-5efe602c3c9b-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d605763e-279e-4cf4-8200-407cd1bc2d0e','11-media-network',NULL,2,'11.8 Cấu trúc 5 tầng','118-cau-truc-5-tang',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7f52c11-3030-49b8-a506-8fdb7dedbc6f','d605763e-279e-4cf4-8200-407cd1bc2d0e',27,'image',NULL,'book/11-media-network/96910621-23f2-4fbb-9904-e0bd8bfcf006-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5712caf7-4088-47d5-8a40-cba834191e93','11-media-network','d605763e-279e-4cf4-8200-407cd1bc2d0e',3,'Tầng 1 và 2: Từ traffic đến trust','tang-1-va-2-tu-traffic-en-trust',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d707dada-0028-4ef2-9703-eb4a4e791ac4','5712caf7-4088-47d5-8a40-cba834191e93',28,'text','**Traffic - Đưa thương hiệu, bác sĩ hoặc phòng khám đến với nhiều người chưa biết mình.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('531c1813-c302-4d2c-bbc6-39b9ab263a92','5712caf7-4088-47d5-8a40-cba834191e93',29,'text','Tầng Traffic có nhiệm vụ đưa thương hiệu, bác sĩ hoặc phòng khám đến với những người chưa biết mình. Nội dung ở tầng này thường là video ngắn 15–60 giây, tập trung vào mẹo chăm sóc răng miệng, giải thích vấn đề đơn giản, chỉ ra sai lầm phổ biến, kể câu chuyện khách hàng hoặc chia sẻ góc nhìn chuyên môn của bác sĩ. Mục tiêu không phải là bán hàng ngay, mà là khiến người xem dừng lại, hiểu vấn đề và bắt đầu chú ý đến thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('87253a5c-bc11-45ff-bb3d-e63d3722b4d7','5712caf7-4088-47d5-8a40-cba834191e93',30,'text','**Kênh chính:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb419964-6723-4be9-b39c-48db531ed8bb','5712caf7-4088-47d5-8a40-cba834191e93',31,'text','- TikTok- Facebook Reels- YouTube Shorts- Zalo Video',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6dbec931-18a8-445c-8edb-23d7b3f97c0f','5712caf7-4088-47d5-8a40-cba834191e93',32,'text','**Loại nội dung phù hợp:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('20f448b6-8721-4686-b854-14f03df531af','5712caf7-4088-47d5-8a40-cba834191e93',33,'text','- Video ngắn 15–60 giây.- Mẹo chăm sóc răng miệng.- Giải thích bệnh răng đơn giản.- Sai lầm phổ biến khi chăm sóc răng.- Case trước - sau, nếu được phép sử dụng hình ảnh.- Câu chuyện khách hàng.- Góc nhìn chuyên môn của bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c23c9ab-61a2-4c14-b669-782b478d3209','5712caf7-4088-47d5-8a40-cba834191e93',34,'text','**Ví dụ nội dung:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca9b3cec-45fa-4d37-a955-53d0f3160cb2','5712caf7-4088-47d5-8a40-cba834191e93',35,'text','- “3 dấu hiệu bạn nên đi lấy cao răng.”- “Vì sao răng ê buốt khi uống nước lạnh?”- “Niềng răng có làm yếu răng không?”- “Mất một răng lâu ngày có nguy hiểm không?”- “Một ca Implant hôm nay có gì đặc biệt?”',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('094606c0-ab61-44ff-8867-79a50abc7822','5712caf7-4088-47d5-8a40-cba834191e93',36,'text','**Nguyên tắc:** Nội dung ở tầng Traffic không nên bán hàng quá sớm. Nhiệm vụ chính là khiến khách hàng dừng lại, hiểu vấn đề và bắt đầu chú ý đến bác sĩ/phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ec55874-6ce8-4038-8439-ee278c6111ef','5712caf7-4088-47d5-8a40-cba834191e93',37,'text','**Trust - Biến người xem thành người tin tưởng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d911f41c-fab3-4b51-88d2-138144060a8d','5712caf7-4088-47d5-8a40-cba834191e93',38,'text','Sau khi đã tạo được sự chú ý, tầng Trust có nhiệm vụ chuyển người xem thành người tin tưởng. Đây là giai đoạn mà các nội dung case điều trị, video bác sĩ tư vấn, feedback khách hàng, hình ảnh đội ngũ và quy trình phòng khám phát huy vai trò mạnh nhất. Trong ngành nha khoa, niềm tin thường được hình thành qua sự xuất hiện đều đặn, tính nhất quán chuyên môn và khả năng diễn đạt dễ hiểu, bởi khách hàng thường mua niềm tin trước khi mua dịch vụ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('df9854fd-f1bc-47ce-a6d0-9cc69b8d6b21','5712caf7-4088-47d5-8a40-cba834191e93',39,'text','**Kênh chính:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f22059fd-86fc-43b9-884b-d4dc429dd4b0','5712caf7-4088-47d5-8a40-cba834191e93',40,'text','- Facebook cá nhân bác sĩ- Fanpage phòng khám- YouTube- Zalo cá nhân- Livestream',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aba19ea9-2a2c-4335-ab96-a9d0d2d74705','5712caf7-4088-47d5-8a40-cba834191e93',41,'text','**Nội dung phù hợp:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd206038-5838-47c6-86cd-2d83f11b09f3','5712caf7-4088-47d5-8a40-cba834191e93',42,'text','- Case điều trị có giải thích chuyên môn.- Video bác sĩ tư vấn.- Feedback khách hàng.- Hình ảnh đội ngũ và quy trình phòng khám.- Nội dung giáo dục chuyên sâu.- Livestream hỏi đáp.- Câu chuyện trước – trong – sau điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd9018a7-6858-43c5-9171-6930e9c3fda7','5712caf7-4088-47d5-8a40-cba834191e93',43,'text','**Nguyên tắc:** Khách hàng nha khoa mua niềm tin trước khi mua dịch vụ. Niềm tin đến từ sự xuất hiện đều đặn, chuyên môn rõ ràng, hình ảnh thật và khả năng giải thích dễ hiểu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6abbae17-3a3f-447d-bdaa-8a98012f4453','11-media-network','d605763e-279e-4cf4-8200-407cd1bc2d0e',3,'Tầng 3: Conversion - Chuyển đổi và hành trình khách hàng','tang-3-conversion-chuyen-oi-va-hanh-trinh-khach-hang',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('505648b6-272a-4e82-9169-860f3149fe11','6abbae17-3a3f-447d-bdaa-8a98012f4453',44,'text','Tầng Conversion là bước chuyển từ sự quan tâm sang hành động cụ thể. Ở tầng này, phòng khám tận dụng Zalo Chat, inbox fanpage, page phòng khám, Google Map, gọi điện và form đặt lịch để hỗ trợ khách hàng chốt lịch hẹn. Hoạt động conversion không chỉ là phản hồi nhanh, mà còn bao gồm tư vấn theo kịch bản, gửi case phù hợp, cung cấp bảng giá tham khảo, giới thiệu địa chỉ, gợi ý khung giờ trống và nhắc lịch trước ngày hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d704b1bf-add0-4083-83a1-612d6310bc7f','6abbae17-3a3f-447d-bdaa-8a98012f4453',45,'text','**Kênh chính:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e477a91f-6a90-491b-b19b-c5e99f3c0cba','6abbae17-3a3f-447d-bdaa-8a98012f4453',46,'text','- Zalo Chat- Inbox Fanpage- Google Map- Gọi điện- Page phòng khám- Form đặt lịch',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4237b888-eaae-4aad-838e-0f0fd6f61b5d','6abbae17-3a3f-447d-bdaa-8a98012f4453',47,'text','**Công việc chính:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4762e375-4897-45bb-b4f0-d27b1cd47b0a','6abbae17-3a3f-447d-bdaa-8a98012f4453',48,'text','- Phản hồi nhanh tin nhắn.- Tư vấn theo kịch bản.- Gửi case phù hợp.- Gửi bảng giá tham khảo nếu cần.- Gửi địa chỉ Google Map.- Gợi ý khung giờ trống.- Nhắc lịch trước ngày hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4949b437-b7e5-4901-9eba-1f073efb2c4d','6abbae17-3a3f-447d-bdaa-8a98012f4453',49,'text','**Nguyên tắc:** Conversion không chỉ là “chốt sale”. Với nha khoa, conversion là quá trình làm khách hàng yên tâm đủ để đến khám trực tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a901a173-b972-4722-a081-765f3203e26b','6abbae17-3a3f-447d-bdaa-8a98012f4453',50,'text','Trong logic học thuật của Dental Empire, customer journey được mô tả theo chuỗi Traffic → Trust → Relationship → Authority Check → Search Layer → Conversion. Chuỗi này cho thấy khách hàng nha khoa hiếm khi đi theo một đường thẳng đơn giản; họ thường quan sát lặp lại, kiểm chứng qua nhiều nguồn và chỉ quyết định khi đã đủ an tâm. Vì vậy, truyền thông không thể chỉ được đo bằng lượt xem hay lượt thích, mà phải được đánh giá bằng khả năng dẫn khách qua từng tầng của hành trình ra quyết định',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('96a1e0cb-ee03-48c5-b827-b606ef4b9414','11-media-network','d605763e-279e-4cf4-8200-407cd1bc2d0e',3,'Tầng 4 và 5: Website, SEO và GEO - Tài sản tìm kiếm dài hạn','tang-4-va-5-website-seo-va-geo-tai-san-tim-kiem-dai-han',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b6215ecb-764a-4651-b5f1-53e51faec4a3','96a1e0cb-ee03-48c5-b827-b606ef4b9414',51,'text','Website là nơi lưu trữ nội dung chuyên sâu, hỗ trợ SEO Google, tích hợp booking và gia tăng độ tin cậy trong quá trình khách hàng tìm kiếm thông tin. Khác với nội dung social có vòng đời ngắn, website và SEO tạo ra tài sản truyền thông dài hạn, có khả năng tiếp tục mang lại khách hàng trong nhiều tháng hoặc nhiều năm. Vì thế, website không phải là “phần phụ”, mà là một lớp nền tảng của hệ sinh thái truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9a1c2454-cb73-4379-b963-aac2fb574453','96a1e0cb-ee03-48c5-b827-b606ef4b9414',52,'text','**Vai trò website:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('addbfcb5-660c-4511-99f8-d9d613e3f070','96a1e0cb-ee03-48c5-b827-b606ef4b9414',53,'text','- Là nơi lưu trữ nội dung chuyên sâu.- Hỗ trợ SEO Google.- Tăng độ tin cậy khi khách hàng tìm kiếm phòng khám.- Tích hợp form đặt lịch.- Giải thích dịch vụ rõ ràng.- Tạo tài sản truyền thông không phụ thuộc hoàn toàn vào nền tảng mạng xã hội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('786f4a51-c4ee-4650-bafd-e42f896b8b1b','96a1e0cb-ee03-48c5-b827-b606ef4b9414',54,'text','**Nội dung website nên có:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5804d66d-ff6d-4640-9fa9-08481bc03fd5','96a1e0cb-ee03-48c5-b827-b606ef4b9414',55,'text','- Trang dịch vụ: Implant, niềng răng, bọc răng sứ, tẩy trắng, nhổ răng khôn, điều trị tủy.- Bài viết kiến thức.- Case study.- Thông tin bác sĩ.- Hình ảnh phòng khám.- Câu hỏi thường gặp.- Form đặt lịch.- Nút gọi điện, Zalo, Google Map.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2faca4fb-89fe-489f-9686-e6b119d90774','96a1e0cb-ee03-48c5-b827-b606ef4b9414',56,'text','GEO, tức Generative Engine Optimization, là bước mở rộng của SEO trong bối cảnh AI Search phát triển. Nếu SEO giúp phòng khám xuất hiện trên Google Search, thì GEO giúp nội dung và thương hiệu có cơ hội được các công cụ AI như ChatGPT, Google Gemini, Google AI Overview, Perplexity, Claude và Bing Copilot hiểu, tổng hợp, trích dẫn và gợi ý. Điều này đặc biệt quan trọng vì hành vi tìm kiếm của khách hàng đã thay đổi: họ không chỉ gõ từ khóa ngắn, mà còn hỏi AI bằng các câu hỏi ngữ cảnh đầy đủ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3269b103-131c-42a5-8872-67f250014a37','96a1e0cb-ee03-48c5-b827-b606ef4b9414',57,'text','**Ví dụ hành vi tìm kiếm mới của khách hàng:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1ca8a1d2-f5e0-471a-9b74-e337d10271bf','96a1e0cb-ee03-48c5-b827-b606ef4b9414',58,'text','Thay vì chỉ gõ Google: "nha khoa implant quận 7"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae631d7c-02bf-449b-a42d-115efdd3a95c','96a1e0cb-ee03-48c5-b827-b606ef4b9414',59,'text','Khách hàng có thể hỏi AI:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7a5a90a-b9b4-4d07-b826-ed297f9402a0','96a1e0cb-ee03-48c5-b827-b606ef4b9414',60,'text','"Tôi ở quận 7, muốn trồng Implant, nên chọn phòng khám như thế nào?
Phòng nha nào có bác sĩ uy tín, review tốt và tư vấn rõ ràng?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f71c477-136b-4034-b552-76bd3e6c3e9b','96a1e0cb-ee03-48c5-b827-b606ef4b9414',61,'text','Trong trường hợp này, AI sẽ ưu tiên tổng hợp thông tin từ những nguồn rõ ràng, đáng tin, có cấu trúc tốt và có nhiều tín hiệu uy tín trên internet.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f6787aa-b305-4029-b1cf-5020e07eaa8d','96a1e0cb-ee03-48c5-b827-b606ef4b9414',62,'text','**GEO không thay thế SEO. GEO mở rộng SEO.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5596bcd5-2bb4-4066-b92c-dceb6418f703','96a1e0cb-ee03-48c5-b827-b606ef4b9414',63,'text','SEO = Tối ưu để Google xếp hạng website
GEO = Tối ưu để AI hiểu, tin, trích dẫn và gợi ý thương hiệu',NULL,NULL,NULL,NULL,NULL);
