INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('446c6cff-c928-41eb-b0e4-932ace8666b0','f0cf27a8-cc86-40c1-ac48-4850802ccbae',65,'text','- Số video đăng mỗi tuần.- Tổng lượt xem.- Tỷ lệ giữ chân video.- Số follower mới.- Số comment/inbox từ video.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5a5521d9-9c3b-4a9d-9f2d-d8e1bc7a7c7a','11-media-network','a78917c5-9b05-4285-b548-9bc5a2ec4e6b',3,'KPI tầng Trust','kpi-tang-trust',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7ad9232-8e2d-439f-a02a-de9786d9771d','5a5521d9-9c3b-4a9d-9f2d-d8e1bc7a7c7a',66,'text','- Số case đăng.- Số feedback đăng.- Lượt tương tác Facebook/Zalo.- Lượt xem livestream.- Số người hỏi thêm sau khi xem nội dung.',NULL,NULL,NULL,NULL,NULL);
