INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4cc626da-9523-43c7-bd9c-11ddb5a6239f','f6ca0267-1ac1-45d9-8b09-ba2f2d8dc18e',67,'text','- Số tin nhắn mới.- Số khách add Zalo.- Tốc độ phản hồi.- Số lịch hẹn được đặt.- Tỷ lệ khách đến đúng hẹn.- Tỷ lệ khách từ tư vấn sang điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4bd4eea4-5d01-4438-a6b1-4952d4b8d58e','11-media-network','a78917c5-9b05-4285-b548-9bc5a2ec4e6b',3,'KPI tầng Website/SEO','kpi-tang-websiteseo',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('99a69e7d-c078-4dd1-a598-bf7631d98609','4bd4eea4-5d01-4438-a6b1-4952d4b8d58e',68,'text','- Lượt truy cập website.- Từ khóa lên top.- Số form booking.- Số cuộc gọi từ website.- Số khách đến từ Google Search/Google Map.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('43184250-41aa-4980-a3d0-a8c9d0d7ab49','11-media-network','a78917c5-9b05-4285-b548-9bc5a2ec4e6b',3,'KPI tầng GEO','kpi-tang-geo',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ecb264a2-e6b9-449e-a9cf-14cef720c3dd','43184250-41aa-4980-a3d0-a8c9d0d7ab49',69,'text','GEO còn mới nên không phải KPI nào cũng đo được chính xác tuyệt đối. Tuy nhiên phòng khám có thể theo dõi các chỉ số sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d0f64fc-abf9-48c3-8256-caf2afd46de4','43184250-41aa-4980-a3d0-a8c9d0d7ab49',70,'text','- Lượt traffic từ nguồn AI/referral nếu có.- Số lần thương hiệu được nhắc đến trong câu trả lời AI khi kiểm tra thủ công.- Số truy vấn thương hiệu tăng lên trên Google Search Console.- Số khách nói rằng họ “hỏi AI”, “tìm trên ChatGPT”, “xem AI gợi ý”.- Số bài FAQ/dịch vụ được cập nhật theo câu hỏi tự nhiên.- Mức độ đồng nhất thông tin phòng khám trên website, Google Map và mạng xã hội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('78c688a0-cbbf-410d-9864-fffadc3b7174','11-media-network',NULL,2,'11.10 Hướng dẫn triển khai sâu từng kênh','1110-huong-dan-trien-khai-sau-tung-kenh',19,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('46f00cb8-df32-46e1-9576-e89306dfb216','11-media-network','78c688a0-cbbf-410d-9864-fffadc3b7174',3,'Zalo - Kênh giữ khách mạnh nhất','zalo-kenh-giu-khach-manh-nhat',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fc8dee14-b778-4ce6-9419-23952e71304c','46f00cb8-df32-46e1-9576-e89306dfb216',71,'text','Trong thị trường Việt Nam, Zalo có vai trò đặc biệt vì đây là nền tảng gắn với **mối quan hệ thật**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ea1f12a9-1d46-4926-bffb-b6a5f280b7f4','46f00cb8-df32-46e1-9576-e89306dfb216',72,'text','**Khác với Facebook, vốn chủ yếu là môi trường tiếp nhận và xem nội dung, Zalo là không gian của quan hệ trực tiếp, chăm sóc cá nhân hóa và chuyển đổi khách hàng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e296e62f-0cda-47bd-86bc-38e9fdfd8dbf','46f00cb8-df32-46e1-9576-e89306dfb216',73,'text','Trên Zalo thường có:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fc685d27-9cb5-4ca4-9f60-df0f2013ca69','46f00cb8-df32-46e1-9576-e89306dfb216',74,'text','- Danh bạ thật.- Khách cũ.- Khách đang điều trị.- Người quen.- Người được giới thiệu.- Khách từng nhắn tin nhưng chưa đặt lịch.- Phụ huynh, người thân của khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d84e76a7-35f9-4059-bb3a-3e4cc7238617','46f00cb8-df32-46e1-9576-e89306dfb216',75,'text','Vì vậy, Zalo thường có tỷ lệ phản hồi và đặt lịch cao hơn nhiều kênh chỉ dùng để xem nội dung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a564c083-f2b5-439f-a552-7a7743c3cbb1','46f00cb8-df32-46e1-9576-e89306dfb216',76,'text','**Vai trò chiến lược của Zalo**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f6fba94-0e92-4a71-a287-fa3d2477ae64','46f00cb8-df32-46e1-9576-e89306dfb216',77,'text','Zalo không chỉ là nơi nhắn tin. Trong Dental Media System, Zalo có 5 vai trò chính:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('95d50040-6ba7-4a27-8b6f-62b74dbd5c0b','46f00cb8-df32-46e1-9576-e89306dfb216',78,'text','- **Giữ liên hệ với khách hàng cũ.**- **Chăm sóc khách đang điều trị.**- **Tạo niềm tin thông qua nội dung cá nhân hóa.**- **Tăng tỷ lệ đặt lịch lại.**- **Khai thác giới thiệu từ người quen và khách hàng hài lòng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('603a7245-8714-488f-a8e5-ba1beb2a0c63','46f00cb8-df32-46e1-9576-e89306dfb216',79,'text','Nếu TikTok giúp phòng khám có người lạ biết đến, thì Zalo giúp giữ họ lại đủ lâu để chuyển đổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62fa4be7-c215-4eb4-8fe1-2d0cca5cb318','46f00cb8-df32-46e1-9576-e89306dfb216',80,'text','**Hai công cụ Zalo cực mạnh cho phòng nha**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b5c400a-cbc8-4a57-8d2a-144a0da0cdb7','46f00cb8-df32-46e1-9576-e89306dfb216',81,'text','- **Tường Zalo / Zalo Feed**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('515c79e9-21f7-472c-abeb-e51bc2215b8e','46f00cb8-df32-46e1-9576-e89306dfb216',82,'text','**Mục tiêu:** Xuất hiện đều đặn trước danh bạ khách hàng và người quen.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6242235-8b03-4f50-ab18-310f06c2be3a','46f00cb8-df32-46e1-9576-e89306dfb216',83,'text','**Dùng để:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0731c34f-a8d7-4192-a6fd-98ab7b55c225','46f00cb8-df32-46e1-9576-e89306dfb216',84,'text','- Đăng case điều trị.- Chia sẻ kiến thức.- Đăng feedback khách hàng.- Thông báo lịch làm việc.- Nhắc lịch chăm sóc răng miệng.- Chia sẻ hoạt động phòng khám.- Xây dựng hình ảnh bác sĩ gần gũi và đáng tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8962ba5d-7466-4a78-b5a5-a36daccdec9a','46f00cb8-df32-46e1-9576-e89306dfb216',85,'text','*Ví dụ nội dung:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e64aa96a-3615-4444-a93f-c9e73a693b96','46f00cb8-df32-46e1-9576-e89306dfb216',86,'text','- “Ca trồng Implant hôm nay: khách mất răng lâu năm, ăn nhai kém.”- “Một sai lầm nhiều người mắc phải khi lấy cao răng.”- “Case chỉnh nha trước – sau sau 18 tháng.”- “Tuần này phòng khám có lịch khám ngoài giờ vào thứ Bảy.”- “Khi nào nên đưa trẻ đi khám răng lần đầu?”',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('299fea82-21bd-43b1-ba12-91e8b1852908','46f00cb8-df32-46e1-9576-e89306dfb216',87,'text','**Tần suất gợi ý:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ef9f276-e2ed-4893-8aab-0a98528a9df1','46f00cb8-df32-46e1-9576-e89306dfb216',88,'text','- 1–2 bài/ngày đối với bác sĩ hoặc tư vấn viên chính.- 3–5 bài/tuần đối với tài khoản phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b440e1a0-2c08-492e-9523-c4775b7b24d2','46f00cb8-df32-46e1-9576-e89306dfb216',89,'text','**Lưu ý:** Nội dung Zalo nên thật, ngắn, gần gũi. Không nên quá giống quảng cáo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2d089fb-5a9e-452f-a413-e3dc9901b1d6','46f00cb8-df32-46e1-9576-e89306dfb216',90,'text','- **Zalo Video Creator**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('edd39e14-c332-42c0-819e-623dcd482e35','46f00cb8-df32-46e1-9576-e89306dfb216',91,'text','**Mục tiêu:** Tạo thêm nguồn traffic nội địa, đặc biệt là khách hàng địa phương.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d9cb103-1444-4128-8dca-9af77763a2e7','46f00cb8-df32-46e1-9576-e89306dfb216',92,'text','Zalo Video Creator có thể xem như một kênh video ngắn trong hệ sinh thái Zalo. Với phòng khám địa phương, đây là kênh đáng khai thác vì mức độ cạnh tranh thường thấp hơn TikTok và Facebook Reels.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a56832c3-a362-4e54-b3bf-d328d494f3b5','46f00cb8-df32-46e1-9576-e89306dfb216',93,'text','**Ưu điểm:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26b89d1d-d500-4953-a9b7-e3b4b5cecc53','46f00cb8-df32-46e1-9576-e89306dfb216',94,'text','- Dễ tiếp cận người dùng địa phương.- Cạnh tranh thấp hơn các nền tảng lớn.- Phù hợp với nội dung ngắn, thực tế.- Tăng khả năng khách add Zalo sau khi xem nội dung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5604c245-a17d-4b02-a761-e88698a69ff3','46f00cb8-df32-46e1-9576-e89306dfb216',95,'text','*Nội dung phù hợp:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34025a43-74eb-4d1f-8002-ff07aeb5b9d5','46f00cb8-df32-46e1-9576-e89306dfb216',96,'text','- Mẹo chăm sóc răng.- Giải thích bệnh răng đơn giản.- Case ngắn 30–60 giây.- Câu hỏi thường gặp.- Video bác sĩ trả lời nhanh.- Video hậu trường phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('14e071e4-cf37-4c8b-94ef-bb9b4825e14f','11-media-network','78c688a0-cbbf-410d-9864-fffadc3b7174',3,'Livestream - Tạo niềm tin và kết nối mạnh nhất','livestream-tao-niem-tin-va-ket-noi-manh-nhat',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b48dd20-086b-46bc-ada8-9694a4405a56','14e071e4-cf37-4c8b-94ef-bb9b4825e14f',97,'text','**Mục tiêu:** Tăng niềm tin nhanh và tạo cơ hội chốt lịch trực tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5208e828-5fe9-44f0-ae91-ac177d29b145','14e071e4-cf37-4c8b-94ef-bb9b4825e14f',98,'text','Livestream nha khoa hiệu quả vì khách hàng có thể:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('858cf560-88d4-4429-b7cb-ff8b4f5b14cd','14e071e4-cf37-4c8b-94ef-bb9b4825e14f',99,'text','- Gặp bác sĩ trực tiếp.- Đặt câu hỏi ngay.- Nghe giải thích chuyên môn dễ hiểu.- Cảm nhận sự thật và sự gần gũi.- Được tư vấn bước tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6b4a98dc-a3b0-4885-9382-cd7ba1edf64e','14e071e4-cf37-4c8b-94ef-bb9b4825e14f',100,'text','**Nội dung livestream phù hợp:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f10b9e43-1824-48d8-9937-4c344e518686','14e071e4-cf37-4c8b-94ef-bb9b4825e14f',101,'text','- Q&A răng miệng.- Phân tích case điều trị.- Tư vấn chỉnh nha.- Giải thích Implant.- Chăm sóc răng cho trẻ em.- Giải đáp hiểu lầm về răng sứ.- Phòng ngừa bệnh nha chu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7b6560b-06f0-418d-9032-2a4626208cc9','14e071e4-cf37-4c8b-94ef-bb9b4825e14f',102,'text','**Cấu trúc livestream 30–45 phút:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('293054a9-8a43-41e3-8f89-04281b3f7538','14e071e4-cf37-4c8b-94ef-bb9b4825e14f',103,'text','- Mở đầu: giới thiệu chủ đề và lợi ích.- Chia sẻ kiến thức chính.- Phân tích 1–2 case thực tế.- Trả lời câu hỏi.- Kêu gọi hành động: nhắn Zalo/inbox để được tư vấn hoặc đặt lịch kiểm tra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3fcdd326-dc33-4562-a21b-3cf00b3b2967','11-media-network','78c688a0-cbbf-410d-9864-fffadc3b7174',3,'Google Map - Điểm chốt niềm tin rất quan trọng','google-map-iem-chot-niem-tin-rat-quan-trong',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e504e049-9b29-4ac0-90fb-b16e797eaea0','3fcdd326-dc33-4562-a21b-3cf00b3b2967',104,'text','Rất nhiều khách hàng trước khi đặt lịch sẽ tìm phòng khám trên Google Map để xem:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4f20848-ca74-4647-a05b-8e65c47361a7','3fcdd326-dc33-4562-a21b-3cf00b3b2967',105,'text','- Phòng khám có thật không?- Địa chỉ có gần không?- Có nhiều đánh giá không?- Hình ảnh có chuyên nghiệp không?- Khách hàng khác nói gì?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('269963ba-3d26-42c5-8194-13a8de355cdf','3fcdd326-dc33-4562-a21b-3cf00b3b2967',106,'text','**Checklist Google Map**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('93e2d5a4-e432-411c-ab71-23630126e455','3fcdd326-dc33-4562-a21b-3cf00b3b2967',107,'text','- Tên phòng khám rõ ràng.- Địa chỉ chính xác.- Số điện thoại đúng.- Giờ mở cửa cập nhật.- Có ảnh mặt tiền, phòng điều trị, bác sĩ, thiết bị.- Có bài đăng định kỳ.- Có review thật.- Phản hồi review lịch sự.- Có link website và Zalo nếu phù hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39ac8fe2-34a5-4f7e-b119-8ad71d6b0784','3fcdd326-dc33-4562-a21b-3cf00b3b2967',108,'text','**Nguyên tắc:** Google Map là nơi xác nhận uy tín trước khi khách quyết định đi đến phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2bf2c858-50f9-4cc9-ba30-cfdcc91fe2e2','11-media-network','78c688a0-cbbf-410d-9864-fffadc3b7174',3,'Website, SEO','website-seo',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14275420-84ba-4ca0-9bc0-df80f9d8e981','2bf2c858-50f9-4cc9-ba30-cfdcc91fe2e2',109,'text','**Website không chỉ để “cho có”**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e8b4fe69-740b-4b60-88f6-691a3183e98e','2bf2c858-50f9-4cc9-ba30-cfdcc91fe2e2',110,'text','Website là tài sản dài hạn. Nội dung trên TikTok, Facebook, Zalo có thể trôi nhanh, nhưng bài viết SEO có thể mang khách hàng trong nhiều tháng hoặc nhiều năm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d5bf9b4-a48b-43d1-af15-5d4724414e7b','2bf2c858-50f9-4cc9-ba30-cfdcc91fe2e2',111,'text','**Nhóm từ khóa nên làm SEO**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f819fb3d-e208-466e-bb56-52922dc32979','2bf2c858-50f9-4cc9-ba30-cfdcc91fe2e2',112,'text','- Nha khoa + khu vực.- Niềng răng + khu vực.- Trồng Implant + khu vực.- Nhổ răng khôn + khu vực.- Lấy cao răng + khu vực.- Bọc răng sứ + khu vực.- Tẩy trắng răng + khu vực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c720f053-b33f-42c3-9745-2fb3021b9a23','2bf2c858-50f9-4cc9-ba30-cfdcc91fe2e2',113,'text','**Cấu trúc bài SEO dịch vụ**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f0af9e6-53fc-4474-8ab9-88e52488fbba','2bf2c858-50f9-4cc9-ba30-cfdcc91fe2e2',114,'text','- Dịch vụ là gì?- Ai nên làm dịch vụ này?- Quy trình thực hiện.- Chi phí tham khảo.- Ưu điểm tại phòng khám.- Câu hỏi thường gặp.- CTA đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('48b7749e-d086-4a47-a707-cd90d4d040f8','11-media-network','78c688a0-cbbf-410d-9864-fffadc3b7174',3,'Vì sao phòng nha cần GEO?','vi-sao-phong-nha-can-geo',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22b51df1-170f-416c-ac5c-d0080c3e612c','48b7749e-d086-4a47-a707-cd90d4d040f8',115,'text','Hành vi tìm kiếm đang thay đổi. Một nhóm khách hàng không chỉ tìm trên Google, mà còn hỏi AI để được tư vấn nhanh, so sánh lựa chọn và hiểu dịch vụ trước khi liên hệ phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d2453fc-b809-465b-b3a4-51ad77320e8b','48b7749e-d086-4a47-a707-cd90d4d040f8',116,'text','Với nha khoa, GEO đặc biệt quan trọng vì khách hàng thường có nhiều câu hỏi trước khi quyết định:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3978a1c-f902-4b07-a04b-22c77b3e6aa0','48b7749e-d086-4a47-a707-cd90d4d040f8',117,'text','- Tôi có nên niềng răng không?- Trồng Implant có đau không?- Nha khoa nào uy tín gần tôi?- Bọc răng sứ có hại không?- Chi phí niềng răng phụ thuộc vào yếu tố nào?- Làm sao chọn bác sĩ chỉnh nha tốt?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4173415f-62f4-4482-9115-2383cda0d29f','48b7749e-d086-4a47-a707-cd90d4d040f8',118,'text','Nếu phòng khám có nội dung rõ ràng, đáng tin và được nhiều nguồn xác nhận, AI có khả năng hiểu phòng khám tốt hơn khi tổng hợp câu trả lời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('863e6fa0-9bf1-4bb6-bd99-483901fdc723','48b7749e-d086-4a47-a707-cd90d4d040f8',119,'text','Các yếu tố giúp GEO hiệu quả cho phòng nha',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9fb6ceaa-5167-4b97-a8ff-65bde6261894','48b7749e-d086-4a47-a707-cd90d4d040f8',120,'text','**Nội dung phải trả lời đúng câu hỏi thật của khách hàng**',NULL,NULL,NULL,NULL,NULL);
