INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96f7a679-2c4d-4b8c-81b4-cff094fc7808','48b7749e-d086-4a47-a707-cd90d4d040f8',122,'text','- “Niềng răng mất bao lâu?”- “Implant có phù hợp với người lớn tuổi không?”- “Lấy cao răng có làm hư men răng không?”- “Bao lâu nên đưa trẻ đi khám răng một lần?”',NULL,NULL,NULL,NULL,NULL);
