INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b152067-ce3f-462b-8bf7-8471f80783ba','48b7749e-d086-4a47-a707-cd90d4d040f8',126,'text','**Tăng tín hiệu chuyên môn của bác sĩ**',NULL,NULL,NULL,NULL,NULL);
