INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f78b0055-29b1-4310-a978-5ce67b5cb747','48b7749e-d086-4a47-a707-cd90d4d040f8',135,'text','Nên có các đoạn định nghĩa, checklist, bảng so sánh và câu trả lời ngắn gọn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('60a1f300-8769-4dfa-b120-bb1d896ecff0','48b7749e-d086-4a47-a707-cd90d4d040f8',136,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fdfb92d7-b8d9-4f76-a01b-413fb16f74fd','48b7749e-d086-4a47-a707-cd90d4d040f8',137,'text','Trồng Implant là phương pháp phục hồi răng mất bằng cách đặt trụ titanium vào xương hàm để thay thế chân răng, sau đó gắn mão răng sứ lên trên nhằm khôi phục khả năng ăn nhai và thẩm mỹ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e1ab9ea-1bb6-4d5d-a2cb-10f663b598b2','48b7749e-d086-4a47-a707-cd90d4d040f8',138,'text','Hoặc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('94490e66-3763-421b-8981-b15183c49013','48b7749e-d086-4a47-a707-cd90d4d040f8',139,'text','Một phòng khám niềng răng uy tín thường cần có bác sĩ chuyên môn chỉnh nha, phim chụp đầy đủ, kế hoạch điều trị rõ ràng, hợp đồng minh bạch và lịch tái khám định kỳ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('191c60e6-5c61-4c08-8959-1792a34f7434','48b7749e-d086-4a47-a707-cd90d4d040f8',140,'text','**Dùng FAQ cho từng dịch vụ**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('565abbfc-04f4-47d6-b6f8-3cf7652e7715','48b7749e-d086-4a47-a707-cd90d4d040f8',141,'text','Mỗi trang dịch vụ nên có 8–15 câu hỏi thường gặp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35eea558-b7e6-4982-b5e2-027bb17a050b','48b7749e-d086-4a47-a707-cd90d4d040f8',142,'text','*Ví dụ với Implant:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2adc3d14-6e14-4a97-a74a-6fb7dcdcf8ec','48b7749e-d086-4a47-a707-cd90d4d040f8',143,'text','- Trồng Implant có đau không?- Trồng Implant mất bao lâu?- Ai không nên trồng Implant?- Implant dùng được bao lâu?- Trồng Implant có cần ghép xương không?- Sau khi cấy Implant cần kiêng gì?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33919911-3e07-4279-b188-ed2198ebd66b','48b7749e-d086-4a47-a707-cd90d4d040f8',144,'text','**Checklist GEO cho phòng nha**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a750447c-531e-423b-af13-66b569781933','48b7749e-d086-4a47-a707-cd90d4d040f8',145,'text','- Website có trang giới thiệu phòng khám rõ ràng.- Có trang hồ sơ bác sĩ.- Có trang dịch vụ chuyên sâu.- Có FAQ cho từng dịch vụ.- Có case study được trình bày rõ.- Có thông tin địa chỉ, số điện thoại, giờ làm việc thống nhất.- Có Google Map đầy đủ ảnh, review và bài đăng.- Có schema/structured data nếu đội kỹ thuật triển khai được.- Có bài viết được cập nhật định kỳ.- Có nội dung trả lời câu hỏi theo ngôn ngữ tự nhiên.- Có video YouTube/Facebook/Zalo liên kết về chủ đề chuyên môn.- Có tín hiệu thương hiệu ngoài website như báo chí, đối tác, nền tảng đặt lịch hoặc thư mục doanh nghiệp uy tín nếu phù hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2345a57b-3c3f-44c2-8133-c05fda1df026','11-media-network','78c688a0-cbbf-410d-9864-fffadc3b7174',3,'Kết nối GEO với Google Map và Review','ket-noi-geo-voi-google-map-va-review',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d253ad5-fe3a-447e-b36f-17119e8d921a','2345a57b-3c3f-44c2-8133-c05fda1df026',146,'text','AI không chỉ đọc website. Các tín hiệu bên ngoài như review, hình ảnh, địa chỉ, đánh giá và sự nhất quán thương hiệu cũng giúp tăng độ tin cậy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('91c8e47c-8d2d-453b-b526-1bf86795ffb8','2345a57b-3c3f-44c2-8133-c05fda1df026',147,'text','Vì vậy, GEO cần đi cùng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a69ea413-7610-4635-a9b3-bc7fc7f8b316','2345a57b-3c3f-44c2-8133-c05fda1df026',148,'text','- Google Map mạnh.- Review thật, đều và có nội dung cụ thể.- Hình ảnh phòng khám thật.- Case thật.- Nội dung bác sĩ thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('358bf924-b0ac-4b61-8687-b55a7165872b','11-media-network','78c688a0-cbbf-410d-9864-fffadc3b7174',3,'Mô hình nội dung SEO + GEO cho một dịch vụ','mo-hinh-noi-dung-seo-geo-cho-mot-dich-vu',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06c83584-1497-469d-a466-ea2144d4ea49','358bf924-b0ac-4b61-8687-b55a7165872b',149,'text','Ví dụ với dịch vụ Implant:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('147218db-4b9e-47d8-8b4c-647f56c08e60','358bf924-b0ac-4b61-8687-b55a7165872b',150,'image',NULL,'book/11-media-network/419d7615-dec6-4098-92c5-b28599903ab7-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cb036d2-72e3-454d-bf6f-fff6d70cf0b8','358bf924-b0ac-4b61-8687-b55a7165872b',151,'text','Khi các nội dung này liên kết với nhau, phòng khám không chỉ mạnh trên Google mà còn có nền tảng tốt hơn để được AI hiểu và tổng hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f7e6fabe-b75c-44ca-8591-2a3427b3fe42','11-media-network',NULL,2,'11.11 Nguyên tắc truyền thông nha khoa tại Việt Nam','1111-nguyen-tac-truyen-thong-nha-khoa-tai-viet-nam',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db011e2a-7d7d-484b-9819-6394c7381b05','f7e6fabe-b75c-44ca-8591-2a3427b3fe42',152,'text','- **Không bán hàng quá sớm: **Hãy giáo dục và xây dựng niềm tin trước.- **Không chỉ chạy theo view:** View cao nhưng không đúng khách hàng thì không tạo doanh thu.- **Bác sĩ là trung tâm niềm tin: **Nội dung có bác sĩ thường tạo uy tín tốt hơn nội dung chỉ dùng hình ảnh chung chung.- **Case thật rất mạnh: **Nhưng cần dùng hình ảnh đúng quy định, có sự đồng ý của khách hàng và tránh cam kết quá mức.- **Zalo phải được chăm đều: **Có data khách nhưng không chăm thì lãng phí rất lớn.- **Google Map phải sạch và đáng tin: **Đây là điểm kiểm tra cuối cùng trước khi khách đến.- **Website là tài sản dài hạn: **Không nên phụ thuộc hoàn toàn vào nền tảng mạng xã hội.- **GEO là lớp tối ưu mới: **Nội dung càng rõ ràng, có cấu trúc, có chuyên môn và đồng nhất thương hiệu, AI càng dễ hiểu và gợi ý phòng khám hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8f4ab18-62d9-4e74-ab94-b405ad84a833','f7e6fabe-b75c-44ca-8591-2a3427b3fe42',153,'image',NULL,'book/11-media-network/6cb3c199-198c-490f-b5c5-d748fda27bbc-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('310e6bc0-4db4-4011-b2d2-946a75bb078d','11-media-network',NULL,2,'11.12 Checklist triển khai hằng ngày','1112-checklist-trien-khai-hang-ngay',28,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5bc0e60f-65f6-4e7e-82e1-76b0a4a006c7','11-media-network','310e6bc0-4db4-4011-b2d2-946a75bb078d',4,'Dành cho Content Team','danh-cho-content-team',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48074d3e-7483-4d5d-b92d-8076d687843d','5bc0e60f-65f6-4e7e-82e1-76b0a4a006c7',154,'text','- Đăng ít nhất 1 video ngắn/ngày.- Cắt lại video cho TikTok, Reels, Shorts, Zalo Video.- Đăng 1 nội dung Zalo Feed/ngày.- Thu thập case và feedback mới.- Kiểm tra comment và inbox từ nội dung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4cd4e129-6df5-42c5-976e-01a9bdffa0c7','11-media-network','310e6bc0-4db4-4011-b2d2-946a75bb078d',4,'Dành cho Tư vấn viên','danh-cho-tu-van-vien',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('faa9a4a6-642e-4eef-9eb5-b296347bc362','4cd4e129-6df5-42c5-976e-01a9bdffa0c7',155,'text','- Phản hồi tin nhắn trong vòng 5–15 phút trong giờ làm việc.- Ghi lại nguồn khách đến từ đâu.- Gửi case phù hợp với nhu cầu khách.- Gợi ý lịch hẹn rõ ràng.- Nhắc lịch trước ngày khám.- Chăm sóc lại khách chưa đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f14dc2d6-ee5f-4764-89e1-d9516c44781e','11-media-network','310e6bc0-4db4-4011-b2d2-946a75bb078d',4,'Dành cho Bác sĩ','danh-cho-bac-si',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c575716c-988d-4b54-8f37-5f9d780853c7','f14dc2d6-ee5f-4764-89e1-d9516c44781e',156,'text','- Quay video giải thích ngắn 3–5 lần/tuần.- Chia sẻ case chuyên môn.- Tham gia Livestream định kỳ.- Xây dựng Zalo/Facebook cá nhân chuyên nghiệp.- Hỗ trợ đội nội dung (content) hiểu đúng chuyên môn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d0ff8d8c-ba99-44d5-b0e1-3bdc627ef713','11-media-network','310e6bc0-4db4-4011-b2d2-946a75bb078d',4,'Dành cho Quản lý phòng khám','danh-cho-quan-ly-phong-kham',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c243cf6-a33a-47a2-ab3a-5d4563862223','d0ff8d8c-ba99-44d5-b0e1-3bdc627ef713',157,'text','- Kiểm tra KPI hằng tuần.- Đánh giá chất lượng tư vấn.- Kiểm tra Google Map và review.- Theo dõi số lịch hẹn từ từng kênh.- Điều chỉnh chiến lược nội dung theo dịch vụ trọng tâm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f66877f9-4bd1-44a2-95f4-430b62d91cc5','11-media-network',NULL,2,'11.13 Vai trò từng nền tảng trong hệ thống','1113-vai-tro-tung-nen-tang-trong-he-thong',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78868736-c2c6-4583-b8c6-7dc869a3ecb3','f66877f9-4bd1-44a2-95f4-430b62d91cc5',158,'image',NULL,'book/11-media-network/7272bfdb-0463-4c70-a457-11692952e388-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8bd1d4da-d5f0-43fb-99c5-d925724fab05','11-media-network',NULL,2,'11.14 Kết chương 11','1114-ket-chuong-11',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3582d77-1dc6-4542-af74-d1c37ebe4ff3','8bd1d4da-d5f0-43fb-99c5-d925724fab05',159,'text','Có thể khẳng định rằng hệ thống truyền thông trong Dental Empire là một cấu phần chiến lược của toàn bộ hệ sinh thái tăng trưởng, không phải một hoạt động marketing đơn lẻ. Nó tổ chức cách phòng khám xuất hiện trên thị trường, cách thương hiệu được nhận biết, cách niềm tin được tạo ra và cách khách hàng được dẫn dắt qua hành trình từ chú ý đến đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e33d14f5-b955-4ce8-9c71-ec6815aab70f','8bd1d4da-d5f0-43fb-99c5-d925724fab05',160,'text','Từ góc độ học thuật, giá trị lớn nhất của Media Network nằm ở khả năng chuyển hóa nội dung thành tài sản, chuyển hóa kênh thành hệ thống, và chuyển hóa sự chú ý thành tăng trưởng bền vững. Khi được vận hành đúng, hệ thống này không chỉ làm tăng số lượng lịch hẹn, mà còn tạo ra một vòng quay tích lũy gồm niềm tin, review, referral, cộng đồng và giá trị thương hiệu dài hạn. Đây chính là nền tảng để phòng khám nha khoa thoát khỏi tư duy truyền thông ngắn hạn và tiến tới mô hình phát triển hệ sinh thái một cách bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('228df266-268b-4ed8-85c3-a9991c9ef804','8bd1d4da-d5f0-43fb-99c5-d925724fab05',161,'text','Đây là một hệ thống có trình tự:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('552a0e8b-3a80-4c95-bb16-eab79acceacb','8bd1d4da-d5f0-43fb-99c5-d925724fab05',162,'text','Thu hút đúng khách hàng
→ Xây dựng niềm tin
→ Giữ quan hệ qua Zalo
→ Xác nhận uy tín bằng Google Map
→ Chuyển đổi qua inbox/gọi điện/booking
→ Tích lũy tài sản dài hạn bằng website và SEO
→ Tối ưu GEO để AI hiểu, trích dẫn và gợi ý phòng khám',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('462ef588-7249-4286-9e1c-e81be9d5b8f8','8bd1d4da-d5f0-43fb-99c5-d925724fab05',163,'text','**Công thức cốt lõi cần nhớ:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33bedf84-d5b6-43a4-8ae0-6b1a9f3e35e7','8bd1d4da-d5f0-43fb-99c5-d925724fab05',164,'image',NULL,'book/11-media-network/7c1d7365-852b-416c-b442-a7443b926337-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd9b7172-8c63-492e-a37b-47f1ff460d3a','8bd1d4da-d5f0-43fb-99c5-d925724fab05',165,'text','Video ngắn tạo chú ý
Facebook/YouTube/Zalo tạo niềm tin
Google Map xác nhận uy tín
Zalo Chat/Inbox/Gọi điện tạo lịch hẹn
Website/SEO tạo tăng trưởng dài hạn
GEO tạo khả năng xuất hiện trong AI Search và câu trả lời của chatbot',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1e2c4fe-7a2e-4c4f-90ca-b474386183eb','8bd1d4da-d5f0-43fb-99c5-d925724fab05',166,'text','**Mục tiêu cuối cùng:** Thu hút đúng khách hàng, tăng niềm tin, tăng số lượng đặt lịch và xây dựng doanh thu bền vững cho phòng khám nha khoa.',NULL,NULL,NULL,NULL,NULL);
